arguments.file_text:
@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" action="/courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search by title, code, or instructor..." />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Search</button>
    </div>
</form>

@if (courses.Count == 0)
{
    <p class="text-muted">No courses found matching your criteria.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.CourseCode</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentName</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }

    private List<Course> courses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.SearchCourses(Search, DepartmentId);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit a request to enroll in a course. You will receive a confirmation from the registrar's office.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for <strong>@selectedCourseName</strong> has been received. The registrar's office will process your request shortly.</p>
        <a href="/courses" class="btn btn-primary">Browse More Courses</a>
    </div>
}
else
{
    <EditForm method="post" Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment" Enhance>
        <DataAnnotationsValidator />
        <AntiforgeryToken />

        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <InputText id="studentName" @bind-Value="Model.StudentName" class="form-control" />
                    <ValidationMessage For="() => Model.StudentName" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" @bind-Value="Model.StudentId" class="form-control" placeholder="e.g., CS123456" />
                    <ValidationMessage For="() => Model.StudentId" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" @bind-Value="Model.CourseId" class="form-select">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.CourseCode — @course.Title (@course.Credits cr)</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.CourseId" />
                </div>

                <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
            </div>
        </div>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private List<Course> courses = new();
    private bool submitted;
    private string selectedCourseName = string.Empty;

    protected override void OnInitialized()
